  // Ranged Weapon Training Level -> { atk, dmg } Bonus.
  //   L0: keine, L1: Proficient (kein Bonus), L2: +1 Atk,
  //   L3: +1 Dmg, L4: +1 Atk (total +2), L5: +1 Dmg (total +2).
  function rwtBonus(level) {
    return {
      atk: (level >= 4) ? 2 : (level >= 2 ? 1 : 0),
      dmg: (level >= 5) ? 2 : (level >= 3 ? 1 : 0),
      proficient: level >= 1,
    };
  }

